@page "/profile"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h3>Roles</h3>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == System.Security.Claims.ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor Page</h1>

<p>Welcome to the editor area. You have the <strong>Editor</strong> role.</p>

@page "/viewer"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Viewer</PageTitle>

<h1>Viewer Page</h1>

<p>This page is accessible to any authenticated user.</p>

